/** Neutral palettes only (low-chroma grays and near-grays). */
export const NEUTRAL_PALETTES = PALETTES.filter((p) => NEUTRAL_NAMES.has(p.name));

/** Chromatic palettes only (everything that isn't a neutral or custom). */
export const CHROMATIC_PALETTES = PALETTES.filter((p) => !NEUTRAL_NAMES.has(p.name) && !CUSTOM_NAMES.has(p.name));

/** Custom palettes only (project-specific, not from Tailwind). */
export const CUSTOM_PALETTES = PALETTES.filter((p) => CUSTOM_NAMES.has(p.name));
